mapper.insert:
INSERT INTO REPORT_BOARD
VALUES
	   (
		  SEQ_PLG_RB.NEXTVAL
	    , #{userId}
	    , #{reportCategory}
	    , #{boardType}
	    , #{content}
	    , SYSDATE
	    , 'N'
	    , 'N'
	    , #{targetNo}
	   )

mapper.select:
SELECT COUNT(*) FROM REPORT_BOARD WHERE DELETED = 'N'
AND UPDATED = #{updated}
AND REPORT_CATEGORY = #{reportCategory}
AND BOARD_TYPE = #{boardType}

SELECT O.REPORT_NO , O.USER_ID , O.REPORT_CATEGORY , O.BOARD_TYPE , O.CONTENT , O.CREATE_DATE , O.UPDATED , O.DELETED , O.TARGET_NO , C.REPORT_COUNT FROM REPORT_BOARD O JOIN (SELECT BOARD_TYPE , TARGET_NO , COUNT(*) AS REPORT_COUNT FROM REPORT_BOARD GROUP BY BOARD_TYPE, TARGET_NO) C ON O.BOARD_TYPE = C.BOARD_TYPE AND O.TARGET_NO = C.TARGET_NO
AND O.UPDATED = #{report.updated}
AND O.REPORT_CATEGORY = #{report.reportCategory}
AND O.BOARD_TYPE = #{report.boardType}
ORDER BY O.REPORT_NO DESC OFFSET #{pi.offset} ROWS FETCH NEXT #{pi.boardLimit} ROWS ONLY
